INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (401, 10046, 24, 0.0, "やったね、ぷうきち！\nこれならお兄ちゃんたちの\nお手本になれたよね！", "2020/07/31 12:00:00", "2030/12/17 14:59:59", 2, "アヤネ", 2, 0.0, 102301, 0.0, 24001);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (402, 10046, 24, 2.21, "私たちの勝ちだね！\nぷうきちと一緒なら\nどんなボールでも\nホームランを打ってみせるよ！", "2020/07/31 12:00:00", "2030/12/17 14:59:59", 2, "アヤネ", 1, 0.0, 102301, 0.0, 24002);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (403, 10046, 24, 0.0, "やったやったぁ！\nお兄ちゃん、見ててくれた？\n私、すっごくがんばったよ！", "2020/07/31 12:00:00", "2030/12/17 14:59:59", 2, "アヤネ", 2, 0.0, 102301, 0.0, 24003);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (701, 10046, 24, 1.99, "特訓の成果が出たみたいだ！\nもっと練習を重ねて\nこの調子で上達していこう！", "2020/07/31 12:00:00", "2030/12/17 14:59:59", 1, "アサヒ", 2, 0.0, 192201, 0.0, 24004);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (702, 10046, 24, 2.21, "よし、いい感じだ！\nキャプテンとしての仕事は\nきっちり果たせそうだよ", "2020/07/31 12:00:00", "2030/12/17 14:59:59", 2, "アサヒ", 1, 0.0, 192201, 0.0, 24005);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (703, 10046, 24, 3.33, "試合に向けて\nいい感覚を掴めた気がするよ！\nこのまま一気に全国大会だ！", "2020/07/31 12:00:00", "2030/12/17 14:59:59", 1, "アサヒ", 2, 0.0, 192201, 0.0, 24006);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (801, 10046, 24, 0.0, "このくらい余裕だ\nオレたちは全国大会を\n目指してるんだからな", "2020/07/31 12:00:00", "2030/12/17 14:59:59", 2, "部員３", 2, 0.0, 192301, 0.0, 24007);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (802, 10046, 24, 2.68, "オレだって\nビーチベースボール選手だ\nどんな球だろうが\n全部スタンドまで飛ばしてやる", "2020/07/31 12:00:00", "2030/12/17 14:59:59", 2, "部員３", 1, 0.0, 192301, 0.0, 24008);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (803, 10046, 24, 0.0, "いい感じだ\nこれなら試合でも活躍できそうだ\n大暴れしてやる！", "2020/07/31 12:00:00", "2030/12/17 14:59:59", 2, "部員３", 2, 0.0, 192301, 0.0, 24009);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (501, 10046, 24, 0.0, "やった！", "2020/07/31 12:00:00", "2030/12/17 14:59:59", 1, "", 1, 0.0, 192501, 0.0, 24010);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (502, 10046, 24, 0.0, "勝ったよ！", "2020/07/31 12:00:00", "2030/12/17 14:59:59", 1, "", 1, 0.0, 192501, 0.0, 24011);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (503, 10046, 24, 0.0, "いい調子！", "2020/07/31 12:00:00", "2030/12/17 14:59:59", 1, "", 1, 0.0, 192501, 0.0, 24012);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (111, 10046, 24, 5.33, "あら～…もしかして\n勝っちゃったのかしら？\nみんなの練習を見ていたから\nかもしれないわね", "2020/07/31 12:00:00", "2030/12/17 14:59:59", 2, "ミサト", 6, 0.0, 113501, 0.0, 24013);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (112, 10046, 24, 6.85, "みんなの力になりたくて\n先生も頑張ってみました～！\nうまく投げられたみたいで\nよかったわ～！", "2020/07/31 12:00:00", "2030/12/17 14:59:59", 2, "ミサト", 1, 0.0, 113501, 0.0, 24014);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (113, 10046, 24, 3.0, "練習お疲れさま～！\n先生も協力できて\nとってもうれしいわ～♪\n次も頑張りましょうね～！", "2020/07/31 12:00:00", "2030/12/17 14:59:59", 2, "ミサト", 1, 0.0, 113501, 0.0, 24015);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (611, 10046, 24, 6.11, "まだ練習が足りねえみてえだな\nこれっぽっちも本気で\n投げてねえっつーの\nもう一回やんぞ！", "2020/07/31 12:00:00", "2030/12/17 14:59:59", 2, "ダイチ", 1, 0.0, 192401, 0.0, 24016);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (612, 10046, 24, 6.75, "ふん、当然の結果だな\n俺の球は、誰にも打てねえよ！\nまたやりてえっつーなら\nとことん付き合ってやるぜ！", "2020/07/31 12:00:00", "2030/12/17 14:59:59", 2, "ダイチ", 1, 0.0, 192401, 0.0, 24017);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (613, 10046, 24, 0.0, "おっしゃあ！\nこの勢いで全国に行ってやるぜ！\n全員三振で仕留めてやる！", "2020/07/31 12:00:00", "2030/12/17 14:59:59", 2, "ダイチ", 2, 0.0, 192401, 0.0, 24018);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (211, 10046, 24, 4.52, "きらーん☆\nハツネちゃんの大勝利なのだ～！\nみんながもっと上達できるように\n私もまだまだ頑張るからね！", "2020/07/31 12:00:00", "2030/12/17 14:59:59", 1, "ハツネ", 2, 0.0, 113401, 0.0, 24019);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (212, 10046, 24, 3.89, "やったあ！　私の勝ちだね！\nチアリーダーもピッチャーも\nハツネちゃんに任せてよ！", "2020/07/31 12:00:00", "2030/12/17 14:59:59", 1, "ハツネ", 2, 0.0, 113401, 0.0, 24020);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (213, 10046, 24, 13.49, "よお～し、この調子でもっと\n頑張ろう…と思ったけど\n超能力を使ったから…\n眠くなってきちゃった…すやぁ…", "2020/07/31 12:00:00", "2030/12/17 14:59:59", 2, "ハツネ", 1, 0.0, 113401, 0.0, 24021);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (311, 10046, 24, 3.17, "いい勝負だったぜ！\nたぎっちまって\nつい本気で投げちまったよ", "2020/07/31 12:00:00", "2030/12/17 14:59:59", 2, "カヤ", 1, 0.0, 106501, 0.0, 24022);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (312, 10046, 24, 4.42, "どうだ？\nオレ様のボールは熱かっただろ！\nま、でもおまえらの根性も\nなかなかのもんだったぜ", "2020/07/31 12:00:00", "2030/12/17 14:59:59", 2, "カヤ", 1, 0.0, 106501, 0.0, 24023);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (313, 10046, 24, 2.89, "なんだよ、そんなもんか？\nこっちはまだまだ投げたりねえ\nもっと勝負しようぜ！", "2020/07/31 12:00:00", "2030/12/17 14:59:59", 1, "カヤ", 6, 0.0, 106501, 0.0, 24024);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (421, 10046, 24, 3.71, "あとちょっとだったのに～！\n次こそぷうきちと一緒に\n勝ってみせるからね！", "2020/07/31 12:00:00", "2030/12/17 14:59:59", 3, "アヤネ", 4, 0.0, 102301, 0.0, 24025);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (721, 10046, 24, 5.1, "いい勝負だったね！\nでも、やっぱり悔しいな…\nもっと練習して\n今度は絶対に俺が勝つから！", "2020/07/31 12:00:00", "2030/12/17 14:59:59", 1, "アサヒ", 2, 0.0, 192201, 0.0, 24026);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (821, 10046, 24, 4.34, "ちっ…あと一歩足りなかったか\n次こそは絶対に勝つから\nそのつもりでいろ", "2020/07/31 12:00:00", "2030/12/17 14:59:59", 3, "部員３", 1, 0.0, 192301, 0.0, 24027);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (521, 10046, 24, 0.0, "いい勝負だったよ\nまたやろうね", "2020/07/31 12:00:00", "2030/12/17 14:59:59", 1, "", 1, 0.0, 192501, 0.0, 24028);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (101, 10046, 24, 5.62, "とってもよくできました～♪\n頑張ってくれて先生うれしいわ\nこれからも試合に向けて\n練習していきましょうね～", "2020/07/31 12:00:00", "2030/12/17 14:59:59", 2, "ミサト", 1, -360.0, 113501, 0.0, 24029);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (102, 10046, 24, 9.58, "頑張った成果ね～！\nこのまま練習を続ければ\nもっとすごい成績を残せそうよ\n期待してますからね～！", "2020/07/31 12:00:00", "2030/12/17 14:59:59", 2, "ミサト", 1, -360.0, 113501, 0.0, 24030);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (103, 10046, 24, 0.0, "いい子、いい子～♪\n頑張り屋さんのあなたを\nたっくさん褒めてあげますからね", "2020/07/31 12:00:00", "2030/12/17 14:59:59", 2, "ミサト", 2, -360.0, 113501, 0.0, 24031);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (104, 10046, 24, 9.13, "夢に向けて、一歩前進できたわね\nこの調子で、夢を叶えましょう\n目指せ、全国大会～！", "2020/07/31 12:00:00", "2030/12/17 14:59:59", 1, "ミサト", 2, -360.0, 113501, 0.0, 24032);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (105, 10046, 24, 8.27, "絶好調ね～♪\nきっと試合でも大活躍\n間違いなしだわ\n楽しみにしていますからね～！", "2020/07/31 12:00:00", "2030/12/17 14:59:59", 2, "ミサト", 1, -360.0, 113501, 0.0, 24033);
